const https = require('https');
const http = require('http');
const { URL } = require('url');
const { JSDOM } = require('jsdom');

const ALLOWED_HOSTS = new Set([
  'www.facebook.com',
  'ogp.me',
  'schema.org',
  'twitter.com',
  'www.twitter.com'
]);

const BLOCKED_IP_RANGES = [
  /^127\./,
  /^10\./,
  /^172\.(1[6-9]|2[0-9]|3[0-1])\./,
  /^192\.168\./,
  /^0\./,
  /^255\./,
  /^169\.254\./
];

function isValidHost(hostname) {
  if (!hostname) return false;
  
  // Check if hostname is in allowed list
  if (ALLOWED_HOSTS.has(hostname)) return true;
  
  // Allow subdomains of allowed hosts
  for (const allowed of ALLOWED_HOSTS) {
    if (hostname.endsWith(`.${allowed}`)) return true;
  }
  
  return false;
}

function isBlockedIP(ip) {
  if (!ip) return true;
  return BLOCKED_IP_RANGES.some(range => range.test(ip));
}

function validateURL(urlString) {
  try {
    const url = new URL(urlString);
    
    if (url.protocol !== 'http:' && url.protocol !== 'https:') {
      throw new Error('Invalid protocol');
    }
    
    if (!isValidHost(url.hostname)) {
      throw new Error('Host not allowed');
    }
    
    return url;
  } catch (error) {
    throw new Error('Invalid URL');
  }
}

function getIPFromHostname(hostname) {
  return new Promise((resolve, reject) => {
    require('dns').lookup(hostname, (err, ip) => {
      if (err) reject(err);
      else resolve(ip);
    });
  });
}

async function fetchMetadata(urlString) {
  const url = validateURL(urlString);
  
  // Validate IP address is not blocked
  try {
    const ip = await getIPFromHostname(url.hostname);
    if (isBlockedIP(ip)) {
      throw new Error('IP address blocked');
    }
  } catch (error) {
    throw new Error('Invalid IP address');
  }
  
  return new Promise((resolve, reject) => {
    const client = url.protocol === 'https:' ? https : http;
    
    const request = client.get(url, (response) => {
      let data = '';
      
      if (response.statusCode !== 200) {
        reject(new Error(`HTTP ${response.statusCode}`));
        return;
      }
      
      response.on('data', (chunk) => {
        data += chunk;
      });
      
      response.on('end', () => {
        try {
          const dom = new JSDOM(data);
          const document = dom.window.document;
          
          const title = document.querySelector('title')?.textContent || '';
          
          const description = 
            document.querySelector('meta[name="description"]')?.getAttribute('content') ||
            document.querySelector('meta[property="og:description"]')?.getAttribute('content') ||
            document.querySelector('meta[name="twitter:description"]')?.getAttribute('content') ||
            '';
          
          const ogTitle = 
            document.querySelector('meta[property="og:title"]')?.getAttribute('content') ||
            '';
          
          const ogDescription = 
            document.querySelector('meta[property="og:description"]')?.getAttribute('content') ||
            '';
          
          const ogImage = 
            document.querySelector('meta[property="og:image"]')?.getAttribute('content') ||
            '';
          
          const ogUrl = 
            document.querySelector('meta[property="og:url"]')?.getAttribute('content') ||
            '';
          
          const twitterTitle = 
            document.querySelector('meta[name="twitter:title"]')?.getAttribute('content') ||
            '';
          
          const twitterDescription = 
            document.querySelector('meta[name="twitter:description"]')?.getAttribute('content') ||
            '';
          
          const twitterImage = 
            document.querySelector('meta[name="twitter:image"]')?.getAttribute('content') ||
            '';
          
          const finalTitle = ogTitle || twitterTitle || title;
          const finalDescription = ogDescription || twitterDescription || description;
          
          resolve({
            title: finalTitle.trim(),
            description: finalDescription.trim(),
            image: ogImage || twitterImage,
            url: ogUrl || urlString,
            originalUrl: urlString
          });
        } catch (error) {
          reject(new Error('Failed to parse HTML'));
        }
      });
    });
    
    request.on('error', (error) => {
      reject(error);
    });
    
    request.setTimeout(10000, () => {
      request.destroy();
      reject(new Error('Request timeout'));
    });
  });
}

exports.fetchMetadata = fetchMetadata;